import styled from 'styled-components';

const PageWrapper = styled.div`
  min-height: 100vh;
  background: ${props => props.theme.background};
  padding-top: 80px;
  transition: background-color 0.3s ease;
  color: ${props => props.theme.text};
`;

export default PageWrapper;
